  1→// Package main implements an MCP (Model Context Protocol) server that exposes
  2→// the Aileron control plane as tools callable by Claude Code and other MCP clients.
  3→//
  4→// It communicates over stdio using JSON-RPC 2.0, per the MCP specification.
  5→//
  6→// Modes:
  7→//   - Embedded (default): runs an in-process Aileron server with in-memory stores.
  8→//   - Remote: set AILERON_API_URL to connect to an existing Aileron server.
  9→package main
 10→
 11→import (
 12→	"bufio"
 13→	"context"
 14→	"encoding/json"
 15→	"fmt"
 16→	"io"
 17→	"log/slog"
 18→	"net"
 19→	"net/http"
 20→	"os"
 21→
 22→	"github.com/ALRubinger/aileron/core/app"
 23→	aileron "github.com/ALRubinger/aileron/sdk/go"
 24→)
 25→
 26→// --- JSON-RPC types ---
 27→
 28→type jsonrpcRequest struct {
 29→	JSONRPC string          `json:"jsonrpc"`
 30→	ID      json.RawMessage `json:"id,omitempty"`
 31→	Method  string          `json:"method"`
 32→	Params  json.RawMessage `json:"params,omitempty"`
 33→}
 34→
 35→type jsonrpcResponse struct {
 36→	JSONRPC string          `json:"jsonrpc"`
 37→	ID      json.RawMessage `json:"id,omitempty"`
 38→	Result  any             `json:"result,omitempty"`
 39→	Error   *jsonrpcError   `json:"error,omitempty"`
 40→}
 41→
 42→type jsonrpcError struct {
 43→	Code    int    `json:"code"`
 44→	Message string `json:"message"`
 45→}
 46→
 47→// --- MCP types ---
 48→
 49→type toolDef struct {
 50→	Name        string    `json:"name"`
 51→	Description string    `json:"description"`
 52→	InputSchema schema    `json:"inputSchema"`
 53→}
 54→
 55→type schema struct {
 56→	Type       string                `json:"type"`
 57→	Properties map[string]schemaProp `json:"properties,omitempty"`
 58→	Required   []string              `json:"required,omitempty"`
 59→}
 60→
 61→type schemaProp struct {
 62→	Type        string `json:"type"`
 63→	Description string `json:"description"`
 64→}
 65→
 66→type callToolParams struct {
 67→	Name      string         `json:"name"`
 68→	Arguments map[string]any `json:"arguments"`
 69→}
 70→
 71→type toolResult struct {
 72→	Content []toolContent `json:"content"`
 73→	IsError bool          `json:"isError,omitempty"`
 74→}
 75→
 76→type toolContent struct {
 77→	Type string `json:"type"`
 78→	Text string `json:"text"`
 79→}
 80→
 81→// --- Server ---
 82→
 83→type server struct {
 84→	client *aileron.Client
 85→}
 86→
 87→func main() {
 88→	apiURL := os.Getenv("AILERON_API_URL")
 89→
 90→	if apiURL == "" {
 91→		// Embedded mode: start an in-process Aileron server on a random port.
 92→		log := slog.New(slog.NewJSONHandler(io.Discard, nil))
 93→		handler, err := app.NewHandler(log)
 94→		if err != nil {
 95→			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to start embedded server: %v\n", err)
 96→			os.Exit(1)
 97→		}
 98→		listener, err := net.Listen("tcp", "127.0.0.1:0")
 99→		if err != nil {
100→			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to listen: %v\n", err)
101→			os.Exit(1)
102→		}
103→		go http.Serve(listener, handler)
104→		apiURL = "http://" + listener.Addr().String()
105→	}
106→
107→	apiKey := os.Getenv("AILERON_API_KEY")
108→	client := aileron.NewClient(apiURL, aileron.WithAPIKey(apiKey))
109→	s := &server{client: client}
110→
111→	scanner := bufio.NewScanner(os.Stdin)
112→	// Increase buffer size for large messages.
113→	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
114→
115→	for scanner.Scan() {
116→		line := scanner.Bytes()
117→		if len(line) == 0 {
118→			continue
119→		}
120→
121→		var req jsonrpcRequest
122→		if err := json.Unmarshal(line, &req); err != nil {
123→			continue
124→		}
125→
126→		resp := s.handle(req)
127→		if resp != nil {
128→			data, _ := json.Marshal(resp)
129→			fmt.Fprintf(os.Stdout, "%s\n", data)
130→		}
131→	}
132→}
133→
134→func (s *server) handle(req jsonrpcRequest) *jsonrpcResponse {
135→	switch req.Method {
136→	case "initialize":
137→		return &jsonrpcResponse{
138→			JSONRPC: "2.0",
139→			ID:      req.ID,
140→			Result: map[string]any{
141→				"protocolVersion": "2024-11-05",
142→				"capabilities": map[string]any{
143→					"tools": map[string]any{},
144→				},
145→				"serverInfo": map[string]any{
146→					"name":    "aileron",
147→					"version": "0.0.1",
148→				},
149→			},
150→		}
151→
152→	case "notifications/initialized":
153→		return nil // no response for notifications
154→
155→	case "tools/list":
156→		return &jsonrpcResponse{
157→			JSONRPC: "2.0",
158→			ID:      req.ID,
159→			Result: map[string]any{
160→				"tools": s.tools(),
161→			},
162→		}
163→
164→	case "tools/call":
165→		var params callToolParams
166→		if err := json.Unmarshal(req.Params, &params); err != nil {
167→			return errorResponse(req.ID, -32602, "invalid params: "+err.Error())
168→		}
169→		result := s.callTool(params)
170→		return &jsonrpcResponse{
171→			JSONRPC: "2.0",
172→			ID:      req.ID,
173→			Result:  result,
174→		}
175→
176→	case "ping":
177→		return &jsonrpcResponse{
178→			JSONRPC: "2.0",
179→			ID:      req.ID,
180→			Result:  map[string]any{},
181→		}
182→
183→	default:
184→		return errorResponse(req.ID, -32601, "method not found: "+req.Method)
185→	}
186→}
187→
188→func (s *server) tools() []toolDef {
189→	return []toolDef{
190→		{
191→			Name:        "submit_intent",
192→			Description: "Submit an action intent to the Aileron control plane for policy evaluation. Returns the disposition (allow/deny/require_approval) and any grant or approval IDs.",
193→			InputSchema: schema{
194→				Type: "object",
195→				Properties: map[string]schemaProp{
196→					"action_type":  {Type: "string", Description: "Dot-namespaced action type, e.g. 'git.pull_request.create', 'payment.charge'"},
197→					"summary":      {Type: "string", Description: "Human-readable summary of what the agent wants to do"},
198→					"justification": {Type: "string", Description: "Why this action is needed"},
199→					"repository":   {Type: "string", Description: "For git actions: owner/repo (e.g. 'acme/checkout')"},
200→					"branch":       {Type: "string", Description: "For git actions: source/head branch"},
201→					"base_branch":  {Type: "string", Description: "For git actions: target/base branch"},
202→					"pr_title":     {Type: "string", Description: "For git PR actions: pull request title"},
203→					"pr_body":      {Type: "string", Description: "For git PR actions: pull request body"},
204→					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
205→				},
206→				Required: []string{"action_type", "summary"},
207→			},
208→		},
209→		{
210→			Name:        "check_approval",
211→			Description: "Check the status of a pending approval request. Returns the current status and, if approved, the execution grant ID.",
212→			InputSchema: schema{
213→				Type: "object",
214→				Properties: map[string]schemaProp{
215→					"approval_id": {Type: "string", Description: "The approval ID to check"},
216→				},
217→				Required: []string{"approval_id"},
218→			},
219→		},
220→		{
221→			Name:        "execute_action",
222→			Description: "Execute an approved action using an execution grant. The grant must be active and not expired.",
223→			InputSchema: schema{
224→				Type: "object",
225→				Properties: map[string]schemaProp{
226→					"grant_id": {Type: "string", Description: "The execution grant ID"},
227→				},
228→				Required: []string{"grant_id"},
229→			},
230→		},
231→		{
232→			Name:        "list_pending_approvals",
233→			Description: "List all pending approval requests in the workspace.",
234→			InputSchema: schema{
235→				Type: "object",
236→				Properties: map[string]schemaProp{
237→					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
238→				},
239→			},
240→		},
241→	}
242→}
243→
244→func (s *server) callTool(params callToolParams) toolResult {
245→	ctx := context.Background()
246→
247→	switch params.Name {
248→	case "submit_intent":
249→		return s.submitIntent(ctx, params.Arguments)
250→	case "check_approval":
251→		return s.checkApproval(ctx, params.Arguments)
252→	case "execute_action":
253→		return s.executeAction(ctx, params.Arguments)
254→	case "list_pending_approvals":
255→		return s.listPendingApprovals(ctx, params.Arguments)
256→	default:
257→		return toolResult{
258→			Content: []toolContent{{Type: "text", Text: "Unknown tool: " + params.Name}},
259→			IsError: true,
260→		}
261→	}
262→}
263→
264→func (s *server) submitIntent(ctx context.Context, args map[string]any) toolResult {
265→	actionType := argStr(args, "action_type")
266→	summary := argStr(args, "summary")
267→	workspaceID := argStr(args, "workspace_id")
268→	if workspaceID == "" {
269→		workspaceID = "default"
270→	}
271→
272→	req := aileron.CreateIntentRequest{
273→		WorkspaceID:    workspaceID,
274→		AgentID:        "claude_code",
275→		IdempotencyKey: fmt.Sprintf("mcp-%s-%d", actionType, os.Getpid()),
276→		Action: aileron.ActionIntent{
277→			Type:    actionType,
278→			Summary: summary,
279→		},
280→		Context: &aileron.IntentContext{
281→			SourcePlatform: strPtr("claude_code"),
282→			UserPresent:    boolPtr(true),
283→		},
284→	}
285→
286→	if just := argStr(args, "justification"); just != "" {
287→		req.Action.Justification = &just
288→	}
289→
290→	// Populate domain-specific fields.
291→	if repo := argStr(args, "repository"); repo != "" {
292→		branch := argStr(args, "branch")
293→		baseBranch := argStr(args, "base_branch")
294→		prTitle := argStr(args, "pr_title")
295→		prBody := argStr(args, "pr_body")
296→		provider := "github"
297→		req.Action.Domain = &aileron.DomainAction{
298→			Git: &aileron.GitAction{
299→				Provider:   &provider,
300→				Repository: &repo,
301→				Branch:     nilIfEmpty(branch),
302→				BaseBranch: nilIfEmpty(baseBranch),
303→				PRTitle:    nilIfEmpty(prTitle),
304→				PRBody:     nilIfEmpty(prBody),
305→			},
306→		}
307→	}
308→
309→	intent, err := s.client.Intents.Create(ctx, req)
310→	if err != nil {
311→		return errorResult("Failed to submit intent: " + err.Error())
312→	}
313→
314→	result := map[string]any{
315→		"intent_id":   intent.IntentID,
316→		"status":      intent.Status,
317→		"disposition": intent.Decision.Disposition,
318→		"risk_level":  intent.Decision.RiskLevel,
319→	}
320→	if intent.Decision.ApprovalID != nil {
321→		result["approval_id"] = *intent.Decision.ApprovalID
322→		result["message"] = fmt.Sprintf("This action requires approval. Approval ID: %s. The user can approve at the Aileron UI.", *intent.Decision.ApprovalID)
323→	}
324→	if intent.Decision.ExecutionGrantID != nil {
325→		result["grant_id"] = *intent.Decision.ExecutionGrantID
326→		result["message"] = "Action approved by policy. Use execute_action with the grant_id to proceed."
327→	}
328→	if intent.Decision.DenialReason != nil {
329→		result["denial_reason"] = *intent.Decision.DenialReason
330→		result["message"] = fmt.Sprintf("Action denied: %s", *intent.Decision.DenialReason)
331→	}
332→
333→	return jsonResult(result)
334→}
335→
336→func (s *server) checkApproval(ctx context.Context, args map[string]any) toolResult {
337→	approvalID := argStr(args, "approval_id")
338→	if approvalID == "" {
339→		return errorResult("approval_id is required")
340→	}
341→
342→	approval, err := s.client.Approvals.Get(ctx, approvalID)
343→	if err != nil {
344→		return errorResult("Failed to get approval: " + err.Error())
345→	}
346→
347→	result := map[string]any{
348→		"approval_id": approval.ApprovalID,
349→		"status":      approval.Status,
350→		"intent_id":   approval.IntentID,
351→	}
352→
353→	switch approval.Status {
354→	case "approved":
355→		// Get the intent to find the grant ID.
356→		intent, err := s.client.Intents.Get(ctx, approval.IntentID)
357→		if err == nil && intent.Decision.ExecutionGrantID != nil {
358→			result["grant_id"] = *intent.Decision.ExecutionGrantID
359→			result["message"] = "Approved! Use execute_action with the grant_id to proceed."
360→		} else {
361→			result["message"] = "Approved, but grant ID not yet available."
362→		}
363→	case "denied":
364→		result["message"] = "The approval request was denied."
365→	case "pending":
366→		result["message"] = "Still waiting for human approval."
367→	default:
368→		result["message"] = "Approval status: " + approval.Status
369→	}
370→
371→	return jsonResult(result)
372→}
373→
374→func (s *server) executeAction(ctx context.Context, args map[string]any) toolResult {
375→	grantID := argStr(args, "grant_id")
376→	if grantID == "" {
377→		return errorResult("grant_id is required")
378→	}
379→
380→	resp, err := s.client.Executions.Run(ctx, aileron.ExecutionRunRequest{
381→		GrantID: grantID,
382→	})
383→	if err != nil {
384→		return errorResult("Failed to execute: " + err.Error())
385→	}
386→
387→	result := map[string]any{
388→		"execution_id": resp.ExecutionID,
389→		"status":       resp.Status,
390→		"message":      "Execution started. ID: " + resp.ExecutionID,
391→	}
392→
393→	// Poll for completion (the execution may complete synchronously).
394→	exec, err := s.client.Executions.Get(ctx, resp.ExecutionID)
395→	if err == nil {
396→		result["status"] = exec.Status
397→		if exec.Output != nil {
398→			result["output"] = *exec.Output
399→		}
400→		if exec.ReceiptRef != nil {
401→			result["receipt_ref"] = *exec.ReceiptRef
402→			result["message"] = "Execution completed. Result: " + *exec.ReceiptRef
403→		}
404→	}
405→
406→	return jsonResult(result)
407→}
408→
409→func (s *server) listPendingApprovals(ctx context.Context, args map[string]any) toolResult {
410→	workspaceID := argStr(args, "workspace_id")
411→	if workspaceID == "" {
412→		workspaceID = "default"
413→	}
414→
415→	resp, err := s.client.Approvals.List(ctx, workspaceID)
416→	if err != nil {
417→		return errorResult("Failed to list approvals: " + err.Error())
418→	}
419→
420→	var pending []map[string]any
421→	for _, a := range resp.Items {
422→		if a.Status == "pending" {
423→			entry := map[string]any{
424→				"approval_id": a.ApprovalID,
425→				"intent_id":   a.IntentID,
426→				"status":      a.Status,
427→				"requested_at": a.RequestedAt.Format("2006-01-02T15:04:05Z"),
428→			}
429→			if a.Rationale != nil {
430→				entry["rationale"] = *a.Rationale
431→			}
432→			pending = append(pending, entry)
433→		}
434→	}
435→
436→	result := map[string]any{
437→		"count":     len(pending),
438→		"approvals": pending,
439→	}
440→	if len(pending) == 0 {
441→		result["message"] = "No pending approvals."
442→	} else {
443→		result["message"] = fmt.Sprintf("%d pending approval(s).", len(pending))
444→	}
445→
446→	return jsonResult(result)
447→}
448→
449→// --- Helpers ---
450→
451→func argStr(args map[string]any, key string) string {
452→	v, ok := args[key]
453→	if !ok {
454→		return ""
455→	}
456→	s, ok := v.(string)
457→	if !ok {
458→		return ""
459→	}
460→	return s
461→}
462→
463→func strPtr(s string) *string   { return &s }
464→func boolPtr(b bool) *bool      { return &b }
465→
466→func nilIfEmpty(s string) *string {
467→	if s == "" {
468→		return nil
469→	}
470→	return &s
471→}
472→
473→func jsonResult(v any) toolResult {
474→	data, _ := json.MarshalIndent(v, "", "  ")
475→	return toolResult{
476→		Content: []toolContent{{Type: "text", Text: string(data)}},
477→	}
478→}
479→
480→func errorResult(msg string) toolResult {
481→	return toolResult{
482→		Content: []toolContent{{Type: "text", Text: msg}},
483→		IsError: true,
484→	}
485→}
486→
487→func errorResponse(id json.RawMessage, code int, msg string) *jsonrpcResponse {
488→	return &jsonrpcResponse{
489→		JSONRPC: "2.0",
490→		ID:      id,
491→		Error:   &jsonrpcError{Code: code, Message: msg},
492→	}
493→}
