281→// flattenIntent creates a flat map of dot-notated fields from an intent
282→// and its context for use in condition evaluation.
283→func flattenIntent(action model.ActionIntent, intentCtx model.IntentContext) map[string]any {
284→	fields := map[string]any{
285→		"action.type":    action.Type,
286→		"action.summary": action.Summary,
287→	}
288→
289→	if action.Target.Kind != "" {
290→		fields["target.kind"] = action.Target.Kind
291→	}
292→	if action.Target.ID != "" {
293→		fields["target.id"] = action.Target.ID
294→	}
295→
296→	// Context fields.
297→	if intentCtx.Environment != "" {
298→		fields["context.environment"] = intentCtx.Environment
299→	}
300→	if intentCtx.SourcePlatform != "" {
301→		fields["context.source_platform"] = intentCtx.SourcePlatform
302→	}
303→
304→	// Domain-specific fields.
305→	if action.Domain.Git != nil {
306→		g := action.Domain.Git
307→		fields["domain.git.provider"] = g.Provider
308→		fields["domain.git.repository"] = g.Repository
309→		fields["domain.git.branch"] = g.Branch
310→		fields["domain.git.base_branch"] = g.BaseBranch
311→		fields["domain.git.pr_title"] = g.PRTitle
312→	}
313→	if action.Domain.Payment != nil {
314→		p := action.Domain.Payment
315→		fields["domain.payment.vendor_name"] = p.VendorName
316→		fields["domain.payment.amount"] = p.Amount.Amount
317→		fields["domain.payment.currency"] = p.Amount.Currency
318→		fields["domain.payment.merchant_category"] = p.MerchantCategory
319→	}
320→	if action.Domain.Calendar != nil {
321→		c := action.Domain.Calendar
322→		fields["domain.calendar.title"] = c.Title
323→		if c.Attendees != nil {
324→			fields["domain.calendar.attendee_count"] = len(c.Attendees)
325→		}
326→	}
327→
328→	return fields
329→}
