 90→func (o *InMemoryOrchestrator) Approve(ctx context.Context, approvalID string, req ApproveRequest) (Approval, error) {
 91→	apiApproval, err := o.approvals.Get(ctx, approvalID)
 92→	if err != nil {
 93→		return Approval{}, err
 94→	}
 95→
 96→	approval := fromAPIApproval(apiApproval)
 97→	if approval.Status != StatusPending {
 98→		return Approval{}, fmt.Errorf("approval: cannot approve %s in state %s", approvalID, approval.Status)
 99→	}
100→
101→	now := time.Now().UTC()
102→	approval.Status = StatusApproved
103→	approval.ResolvedAt = &now
104→
105→	// Mark all actors as approved.
106→	for i := range approval.Approvers {
107→		approval.Approvers[i].Status = ActorStatusApproved
108→	}
109→
110→	if err := o.approvals.Update(ctx, toAPIApproval(approval)); err != nil {
111→		return Approval{}, fmt.Errorf("approval: update: %w", err)
112→	}
113→
114→	return approval, nil
115→}
