  1→// Package aileron provides a Go client for the Aileron control plane API.
  2→//
  3→// Usage:
  4→//
  5→//	client := aileron.NewClient("https://api.example.com", aileron.WithAPIKey("..."))
  6→//	intent, err := client.Intents.Create(ctx, aileron.CreateIntentRequest{ ... })
  7→package aileron
  8→
  9→import (
 10→	"bytes"
 11→	"context"
 12→	"encoding/json"
 13→	"fmt"
 14→	"io"
 15→	"net/http"
 16→	"time"
 17→)
 18→
 19→// Client is the Aileron API client.
 20→type Client struct {
 21→	baseURL    string
 22→	httpClient *http.Client
 23→	apiKey     string
 24→
 25→	Intents    *IntentsService
 26→	Approvals  *ApprovalsService
 27→	Policies   *PoliciesService
 28→	Executions *ExecutionsService
 29→}
 30→
 31→// Option configures the client.
 32→type Option func(*Client)
 33→
 34→// WithAPIKey sets the API key for authentication.
 35→func WithAPIKey(key string) Option {
 36→	return func(c *Client) {
 37→		c.apiKey = key
 38→	}
 39→}
 40→
 41→// WithHTTPClient sets a custom HTTP client.
 42→func WithHTTPClient(hc *http.Client) Option {
 43→	return func(c *Client) {
 44→		c.httpClient = hc
 45→	}
 46→}
 47→
 48→// NewClient returns a new Aileron API client.
 49→func NewClient(baseURL string, opts ...Option) *Client {
 50→	c := &Client{
 51→		baseURL: baseURL,
 52→		httpClient: &http.Client{
 53→			Timeout: 30 * time.Second,
 54→		},
 55→	}
 56→	for _, opt := range opts {
 57→		opt(c)
 58→	}
 59→
 60→	c.Intents = &IntentsService{client: c}
 61→	c.Approvals = &ApprovalsService{client: c}
 62→	c.Policies = &PoliciesService{client: c}
 63→	c.Executions = &ExecutionsService{client: c}
 64→
 65→	return c
 66→}
 67→
 68→func (c *Client) do(ctx context.Context, method, path string, body, result any) error {
 69→	var bodyReader io.Reader
 70→	if body != nil {
 71→		data, err := json.Marshal(body)
 72→		if err != nil {
 73→			return fmt.Errorf("marshal request: %w", err)
 74→		}
 75→		bodyReader = bytes.NewReader(data)
 76→	}
 77→
 78→	req, err := http.NewRequestWithContext(ctx, method, c.baseURL+path, bodyReader)
 79→	if err != nil {
 80→		return fmt.Errorf("create request: %w", err)
 81→	}
 82→	req.Header.Set("Content-Type", "application/json")
 83→	if c.apiKey != "" {
 84→		req.Header.Set("Authorization", "Bearer "+c.apiKey)
 85→	}
 86→
 87→	resp, err := c.httpClient.Do(req)
 88→	if err != nil {
 89→		return fmt.Errorf("http request: %w", err)
 90→	}
 91→	defer resp.Body.Close()
 92→
 93→	respBody, err := io.ReadAll(resp.Body)
 94→	if err != nil {
 95→		return fmt.Errorf("read response: %w", err)
 96→	}
 97→
 98→	if resp.StatusCode >= 400 {
 99→		return fmt.Errorf("API error %d: %s", resp.StatusCode, string(respBody))
100→	}
101→
102→	if result != nil && len(respBody) > 0 {
103→		if err := json.Unmarshal(respBody, result); err != nil {
104→			return fmt.Errorf("unmarshal response: %w", err)
105→		}
106→	}
107→	return nil
108→}
109→
