137→	Repository *string  `json:"repository,omitempty"`
138→	Branch     *string  `json:"branch,omitempty"`
139→	BaseBranch *string  `json:"base_branch,omitempty"`
140→	PRTitle    *string  `json:"pr_title,omitempty"`
141→	PRBody     *string  `json:"pr_body,omitempty"`
142→	Labels     []string `json:"labels,omitempty"`
