  1→// Package main implements an MCP (Model Context Protocol) server that exposes
  2→// the Aileron control plane as tools callable by Claude Code and other MCP clients.
  3→//
  4→// It communicates over stdio using JSON-RPC 2.0, per the MCP specification.
  5→//
  6→// Modes:
  7→//   - Embedded (default): runs an in-process Aileron server with in-memory stores.
  8→//   - Remote: set AILERON_API_URL to connect to an existing Aileron server.
  9→package main
 10→
 11→import (
 12→	"bufio"
 13→	"context"
 14→	"encoding/json"
 15→	"fmt"
 16→	"io"
 17→	"log/slog"
 18→	"net"
 19→	"net/http"
 20→	"os"
 21→
 22→	"github.com/ALRubinger/aileron/core/app"
 23→	aileron "github.com/ALRubinger/aileron/sdk/go"
 24→)
 25→
 26→// --- JSON-RPC types ---
 27→
 28→type jsonrpcRequest struct {
 29→	JSONRPC string          `json:"jsonrpc"`
 30→	ID      json.RawMessage `json:"id,omitempty"`
 31→	Method  string          `json:"method"`
 32→	Params  json.RawMessage `json:"params,omitempty"`
 33→}
 34→
 35→type jsonrpcResponse struct {
 36→	JSONRPC string          `json:"jsonrpc"`
 37→	ID      json.RawMessage `json:"id,omitempty"`
 38→	Result  any             `json:"result,omitempty"`
 39→	Error   *jsonrpcError   `json:"error,omitempty"`
 40→}
 41→
 42→type jsonrpcError struct {
 43→	Code    int    `json:"code"`
 44→	Message string `json:"message"`
 45→}
 46→
 47→// --- MCP types ---
 48→
 49→type toolDef struct {
 50→	Name        string    `json:"name"`
 51→	Description string    `json:"description"`
 52→	InputSchema schema    `json:"inputSchema"`
 53→}
 54→
 55→type schema struct {
 56→	Type       string                `json:"type"`
 57→	Properties map[string]schemaProp `json:"properties,omitempty"`
 58→	Required   []string              `json:"required,omitempty"`
 59→}
 60→
 61→type schemaProp struct {
 62→	Type        string `json:"type"`
 63→	Description string `json:"description"`
 64→}
 65→
 66→type callToolParams struct {
 67→	Name      string         `json:"name"`
 68→	Arguments map[string]any `json:"arguments"`
 69→}
 70→
 71→type toolResult struct {
 72→	Content []toolContent `json:"content"`
 73→	IsError bool          `json:"isError,omitempty"`
 74→}
 75→
 76→type toolContent struct {
 77→	Type string `json:"type"`
 78→	Text string `json:"text"`
 79→}
 80→
 81→// --- Server ---
 82→
 83→type server struct {
 84→	client *aileron.Client
 85→}
 86→
 87→func main() {
 88→	apiURL := os.Getenv("AILERON_API_URL")
 89→
 90→	if apiURL == "" {
 91→		// Embedded mode: start an in-process Aileron server on a random port.
 92→		log := slog.New(slog.NewJSONHandler(io.Discard, nil))
 93→		handler, err := app.NewHandler(log)
 94→		if err != nil {
 95→			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to start embedded server: %v\n", err)
 96→			os.Exit(1)
 97→		}
 98→		listener, err := net.Listen("tcp", "127.0.0.1:0")
 99→		if err != nil {
100→			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to listen: %v\n", err)
101→			os.Exit(1)
102→		}
103→		go http.Serve(listener, handler)
104→		apiURL = "http://" + listener.Addr().String()
105→	}
106→
107→	apiKey := os.Getenv("AILERON_API_KEY")
108→	client := aileron.NewClient(apiURL, aileron.WithAPIKey(apiKey))
109→	s := &server{client: client}
110→
111→	scanner := bufio.NewScanner(os.Stdin)
112→	// Increase buffer size for large messages.
113→	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)
114→
115→	for scanner.Scan() {
116→		line := scanner.Bytes()
117→		if len(line) == 0 {
118→			continue
119→		}
120→
121→		var req jsonrpcRequest
122→		if err := json.Unmarshal(line, &req); err != nil {
123→			continue
124→		}
125→
126→		resp := s.handle(req)
127→		if resp != nil {
128→			data, _ := json.Marshal(resp)
129→			fmt.Fprintf(os.Stdout, "%s\n", data)
130→		}
131→	}
132→}
133→
134→func (s *server) handle(req jsonrpcRequest) *jsonrpcResponse {
135→	switch req.Method {
136→	case "initialize":
137→		return &jsonrpcResponse{
138→			JSONRPC: "2.0",
139→			ID:      req.ID,
140→			Result: map[string]any{
141→				"protocolVersion": "2024-11-05",
142→				"capabilities": map[string]any{
143→					"tools": map[string]any{},
144→				},
145→				"serverInfo": map[string]any{
146→					"name":    "aileron",
147→					"version": "0.0.1",
148→				},
149→			},
150→		}
151→
152→	case "notifications/initialized":
153→		return nil // no response for notifications
154→
155→	case "tools/list":
156→		return &jsonrpcResponse{
157→			JSONRPC: "2.0",
158→			ID:      req.ID,
159→			Result: map[string]any{
160→				"tools": s.tools(),
161→			},
162→		}
163→
164→	case "tools/call":
165→		var params callToolParams
166→		if err := json.Unmarshal(req.Params, &params); err != nil {
167→			return errorResponse(req.ID, -32602, "invalid params: "+err.Error())
168→		}
169→		result := s.callTool(params)
170→		return &jsonrpcResponse{
171→			JSONRPC: "2.0",
172→			ID:      req.ID,
173→			Result:  result,
174→		}
175→
176→	case "ping":
177→		return &jsonrpcResponse{
178→			JSONRPC: "2.0",
179→			ID:      req.ID,
180→			Result:  map[string]any{},
181→		}
182→
183→	default:
184→		return errorResponse(req.ID, -32601, "method not found: "+req.Method)
185→	}
186→}
187→
188→func (s *server) tools() []toolDef {
189→	return []toolDef{
190→		{
191→			Name:        "submit_intent",
192→			Description: "Submit an action intent to the Aileron control plane for policy evaluation. Returns the disposition (allow/deny/require_approval) and any grant or approval IDs.",
193→			InputSchema: schema{
194→				Type: "object",
195→				Properties: map[string]schemaProp{
196→					"action_type":  {Type: "string", Description: "Dot-namespaced action type, e.g. 'git.pull_request.create', 'payment.charge'"},
197→					"summary":      {Type: "string", Description: "Human-readable summary of what the agent wants to do"},
198→					"justification": {Type: "string", Description: "Why this action is needed"},
199→					"repository":   {Type: "string", Description: "For git actions: owner/repo (e.g. 'acme/checkout')"},
200→					"branch":       {Type: "string", Description: "For git actions: source/head branch"},
201→					"base_branch":  {Type: "string", Description: "For git actions: target/base branch"},
202→					"pr_title":     {Type: "string", Description: "For git PR actions: pull request title"},
203→					"pr_body":      {Type: "string", Description: "For git PR actions: pull request body"},
204→					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
205→				},
206→				Required: []string{"action_type", "summary"},
207→			},
208→		},
209→		{
210→			Name:        "check_approval",
211→			Description: "Check the status of a pending approval request. Returns the current status and, if approved, the execution grant ID.",
212→			InputSchema: schema{
213→				Type: "object",
214→				Properties: map[string]schemaProp{
215→					"approval_id": {Type: "string", Description: "The approval ID to check"},
216→				},
217→				Required: []string{"approval_id"},
218→			},
