 3→import (
 4→	"context"
 5→	"sync"
 6→
 7→	api "github.com/ALRubinger/aileron/core/api/gen"
 8→	"github.com/ALRubinger/aileron/core/store"
 9→)
10→
11→// TraceStore is a thread-safe in-memory append-only trace store.
12→type TraceStore struct {
13→	mu     sync.RWMutex
14→	traces map[string]*api.Trace // keyed by intent_id
15→}
16→
17→// NewTraceStore returns an empty in-memory trace store.
18→func NewTraceStore() *TraceStore {
19→	return &TraceStore{traces: make(map[string]*api.Trace)}
20→}
21→
22→// Append adds an event to the trace for the given intent.
23→// If no trace exists, a new one is created.
24→func (s *TraceStore) Append(_ context.Context, intentID, workspaceID, traceID string, event api.TraceEvent) error {
25→	s.mu.Lock()
26→	defer s.mu.Unlock()
27→	t, ok := s.traces[intentID]
28→	if !ok {
29→		wsID := workspaceID
30→		t = &api.Trace{
31→			TraceId:     traceID,
32→			IntentId:    intentID,
33→			WorkspaceId: &wsID,
34→			Events:      []api.TraceEvent{},
35→		}
36→		s.traces[intentID] = t
37→	}
38→	t.Events = append(t.Events, event)
39→	return nil
40→}
41→
42→// GetByIntent returns the trace for a given intent ID.
43→func (s *TraceStore) GetByIntent(_ context.Context, intentID string) (api.Trace, error) {
44→	s.mu.RLock()
45→	defer s.mu.RUnlock()
46→	t, ok := s.traces[intentID]
47→	if !ok {
48→		return api.Trace{}, &store.ErrNotFound{Entity: "trace", ID: intentID}
49→	}
50→	return *t, nil
51→}
52→
53→// List returns all traces, optionally filtered.
54→func (s *TraceStore) List(_ context.Context, filter TraceFilter) ([]api.Trace, error) {
55→	s.mu.RLock()
56→	defer s.mu.RUnlock()
57→	var result []api.Trace
58→	for _, t := range s.traces {
59→		if filter.WorkspaceID != "" {
60→			if t.WorkspaceId == nil || *t.WorkspaceId != filter.WorkspaceID {
61→				continue
62→			}
63→		}
64→		if filter.IntentID != "" && t.IntentId != filter.IntentID {
65→			continue
66→		}
67→		result = append(result, *t)
68→	}
69→	return result, nil
70→}
71→
72→// TraceFilter scopes a trace list query.
73→type TraceFilter struct {
74→	WorkspaceID string
75→	IntentID    string
76→	PageSize    int
77→	PageToken   string
78→}
