244→func (s *server) callTool(params callToolParams) toolResult {
245→	ctx := context.Background()
246→
247→	switch params.Name {
248→	case "submit_intent":
249→		return s.submitIntent(ctx, params.Arguments)
250→	case "check_approval":
251→		return s.checkApproval(ctx, params.Arguments)
252→	case "execute_action":
253→		return s.executeAction(ctx, params.Arguments)
254→	case "list_pending_approvals":
255→		return s.listPendingApprovals(ctx, params.Arguments)
256→	default:
257→		return toolResult{
258→			Content: []toolContent{{Type: "text", Text: "Unknown tool: " + params.Name}},
259→			IsError: true,
260→		}
261→	}
262→}
263→
264→func (s *server) submitIntent(ctx context.Context, args map[string]any) toolResult {
265→	actionType := argStr(args, "action_type")
266→	summary := argStr(args, "summary")
267→	workspaceID := argStr(args, "workspace_id")
268→	if workspaceID == "" {
269→		workspaceID = "default"
270→	}
271→
272→	req := aileron.CreateIntentRequest{
273→		WorkspaceID:    workspaceID,
274→		AgentID:        "claude_code",
275→		IdempotencyKey: fmt.Sprintf("mcp-%s-%d", actionType, os.Getpid()),
276→		Action: aileron.ActionIntent{
277→			Type:    actionType,
278→			Summary: summary,
279→		},
280→		Context: &aileron.IntentContext{
281→			SourcePlatform: strPtr("claude_code"),
282→			UserPresent:    boolPtr(true),
283→		},
284→	}
285→
286→	if just := argStr(args, "justification"); just != "" {
287→		req.Action.Justification = &just
288→	}
289→
290→	// Populate domain-specific fields.
291→	if repo := argStr(args, "repository"); repo != "" {
292→		branch := argStr(args, "branch")
293→		baseBranch := argStr(args, "base_branch")
294→		prTitle := argStr(args, "pr_title")
295→		prBody := argStr(args, "pr_body")
296→		provider := "github"
297→		req.Action.Domain = &aileron.DomainAction{
298→			Git: &aileron.GitAction{
299→				Provider:   &provider,
300→				Repository: &repo,
301→				Branch:     nilIfEmpty(branch),
302→				BaseBranch: nilIfEmpty(baseBranch),
303→				PRTitle:    nilIfEmpty(prTitle),
304→				PRBody:     nilIfEmpty(prBody),
305→			},
306→		}
307→	}
308→
309→	intent, err := s.client.Intents.Create(ctx, req)
310→	if err != nil {
311→		return errorResult("Failed to submit intent: " + err.Error())
312→	}
313→
314→	result := map[string]any{
315→		"intent_id":   intent.IntentID,
316→		"status":      intent.Status,
317→		"disposition": intent.Decision.Disposition,
318→		"risk_level":  intent.Decision.RiskLevel,
319→	}
320→	if intent.Decision.ApprovalID != nil {
321→		result["approval_id"] = *intent.Decision.ApprovalID
322→		result["message"] = fmt.Sprintf("This action requires approval. Approval ID: %s. The user can approve at the Aileron UI.", *intent.Decision.ApprovalID)
323→	}
324→	if intent.Decision.ExecutionGrantID != nil {
325→		result["grant_id"] = *intent.Decision.ExecutionGrantID
326→		result["message"] = "Action approved by policy. Use execute_action with the grant_id to proceed."
327→	}
328→	if intent.Decision.DenialReason != nil {
329→		result["denial_reason"] = *intent.Decision.DenialReason
330→		result["message"] = fmt.Sprintf("Action denied: %s", *intent.Decision.DenialReason)
331→	}
332→
333→	return jsonResult(result)
334→}
335→
336→func (s *server) checkApproval(ctx context.Context, args map[string]any) toolResult {
337→	approvalID := argStr(args, "approval_id")
338→	if approvalID == "" {
339→		return errorResult("approval_id is required")
340→	}
341→
342→	approval, err := s.client.Approvals.Get(ctx, approvalID)
343→	if err != nil {
344→		return errorResult("Failed to get approval: " + err.Error())
345→	}
346→
347→	result := map[string]any{
348→		"approval_id": approval.ApprovalID,
349→		"status":      approval.Status,
350→		"intent_id":   approval.IntentID,
351→	}
352→
353→	switch approval.Status {
354→	case "approved":
355→		// Get the intent to find the grant ID.
356→		intent, err := s.client.Intents.Get(ctx, approval.IntentID)
357→		if err == nil && intent.Decision.ExecutionGrantID != nil {
358→			result["grant_id"] = *intent.Decision.ExecutionGrantID
359→			result["message"] = "Approved! Use execute_action with the grant_id to proceed."
360→		} else {
361→			result["message"] = "Approved, but grant ID not yet available."
362→		}
363→	case "denied":
364→		result["message"] = "The approval request was denied."
365→	case "pending":
366→		result["message"] = "Still waiting for human approval."
367→	default:
368→		result["message"] = "Approval status: " + approval.Status
369→	}
370→
371→	return jsonResult(result)
372→}
373→
374→func (s *server) executeAction(ctx context.Context, args map[string]any) toolResult {
375→	grantID := argStr(args, "grant_id")
376→	if grantID == "" {
377→		return errorResult("grant_id is required")
378→	}
379→
380→	resp, err := s.client.Executions.Run(ctx, aileron.ExecutionRunRequest{
381→		GrantID: grantID,
382→	})
383→	if err != nil {
384→		return errorResult("Failed to execute: " + err.Error())
385→	}
386→
387→	result := map[string]any{
388→		"execution_id": resp.ExecutionID,
389→		"status":       resp.Status,
390→		"message":      "Execution started. ID: " + resp.ExecutionID,
391→	}
392→
393→	// Poll for completion (the execution may complete synchronously).
394→	exec, err := s.client.Executions.Get(ctx, resp.ExecutionID)
395→	if err == nil {
396→		result["status"] = exec.Status
397→		if exec.Output != nil {
398→			result["output"] = *exec.Output
399→		}
400→		if exec.ReceiptRef != nil {
401→			result["receipt_ref"] = *exec.ReceiptRef
402→			result["message"] = "Execution completed. Result: " + *exec.ReceiptRef
403→		}
404→	}
405→
406→	return jsonResult(result)
407→}
408→
409→func (s *server) listPendingApprovals(ctx context.Context, args map[string]any) toolResult {
410→	workspaceID := argStr(args, "workspace_id")
411→	if workspaceID == "" {
412→		workspaceID = "default"
413→	}
414→
415→	resp, err := s.client.Approvals.List(ctx, workspaceID)
416→	if err != nil {
417→		return errorResult("Failed to list approvals: " + err.Error())
418→	}
419→
420→	var pending []map[string]any
421→	for _, a := range resp.Items {
422→		if a.Status == "pending" {
423→			entry := map[string]any{
424→				"approval_id": a.ApprovalID,
425→				"intent_id":   a.IntentID,
426→				"status":      a.Status,
427→				"requested_at": a.RequestedAt.Format("2006-01-02T15:04:05Z"),
428→			}
429→			if a.Rationale != nil {
430→				entry["rationale"] = *a.Rationale
431→			}
432→			pending = append(pending, entry)
433→		}
434→	}
435→
436→	result := map[string]any{
437→		"count":     len(pending),
438→		"approvals": pending,
439→	}
440→	if len(pending) == 0 {
441→		result["message"] = "No pending approvals."
442→	} else {
443→		result["message"] = fmt.Sprintf("%d pending approval(s).", len(pending))
444→	}
445→
446→	return jsonResult(result)
447→}
