449→// --- Helpers ---
450→
451→func argStr(args map[string]any, key string) string {
452→	v, ok := args[key]
453→	if !ok {
454→		return ""
455→	}
456→	s, ok := v.(string)
457→	if !ok {
458→		return ""
459→	}
460→	return s
461→}
462→
463→func strPtr(s string) *string   { return &s }
464→func boolPtr(b bool) *bool      { return &b }
465→
466→func nilIfEmpty(s string) *string {
467→	if s == "" {
468→		return nil
469→	}
470→	return &s
471→}
472→
473→func jsonResult(v any) toolResult {
474→	data, _ := json.MarshalIndent(v, "", "  ")
475→	return toolResult{
476→		Content: []toolContent{{Type: "text", Text: string(data)}},
477→	}
478→}
479→
480→func errorResult(msg string) toolResult {
481→	return toolResult{
482→		Content: []toolContent{{Type: "text", Text: msg}},
483→		IsError: true,
484→	}
485→}
486→
487→func errorResponse(id json.RawMessage, code int, msg string) *jsonrpcResponse {
488→	return &jsonrpcResponse{
489→		JSONRPC: "2.0",
490→		ID:      id,
491→		Error:   &jsonrpcError{Code: code, Message: msg},
492→	}
493→}
