 15→// RuleEngine evaluates policy rules from the policy store against intents.
 16→type RuleEngine struct {
 17→	policies store.PolicyStore
 18→}
 19→
 20→// NewRuleEngine returns a policy engine backed by the given store.
 21→func NewRuleEngine(policies store.PolicyStore) *RuleEngine {
 22→	return &RuleEngine{policies: policies}
 23→}
 24→
 25→// Evaluate implements Engine.
 26→func (e *RuleEngine) Evaluate(ctx context.Context, req EvaluationRequest) (model.Decision, error) {
 27→	// Load all active policies for the workspace.
 28→	activeStatus := api.PolicyStatusActive
 29→	policies, err := e.policies.List(ctx, store.PolicyFilter{
 30→		WorkspaceID: req.WorkspaceID,
 31→		Status:      &activeStatus,
 32→	})
 33→	if err != nil {
 34→		return model.Decision{}, fmt.Errorf("policy: list policies: %w", err)
 35→	}
 36→
 37→	// Flatten to intent fields for condition evaluation.
 38→	fields := flattenIntent(req.Action, req.Context)
 39→
 40→	// Collect all matching rules across policies, sorted by priority.
 41→	type match struct {
 42→		policy api.Policy
 43→		rule   api.PolicyRule
 44→	}
 45→	var matches []match
 46→
 47→	for _, p := range policies {
 48→		for _, r := range p.Rules {
 49→			if !actionTypeMatches(req.Action.Type, r) {
 50→				continue
 51→			}
 52→			if !conditionsMatch(r.Conditions, fields) {
 53→				continue
 54→			}
 55→			matches = append(matches, match{policy: p, rule: r})
 56→		}
 57→	}
 58→
 59→	if len(matches) == 0 {
 60→		// Default: allow with low risk when no rules match.
 61→		return model.Decision{
 62→			Disposition: model.DispositionAllow,
 63→			RiskLevel:   model.RiskLevelLow,
 64→		}, nil
 65→	}
 66→
 67→	// Sort by priority descending (higher priority wins).
 68→	sort.Slice(matches, func(i, j int) bool {
 69→		pi, pj := 0, 0
 70→		if matches[i].rule.Priority != nil {
 71→			pi = *matches[i].rule.Priority
 72→		}
 73→		if matches[j].rule.Priority != nil {
 74→			pj = *matches[j].rule.Priority
 75→		}
 76→		return pi > pj
 77→	})
 78→
 79→	winner := matches[0]
 80→	disposition := effectToDisposition(winner.rule.Effect)
 81→	riskLevel := effectToRiskLevel(winner.rule.Effect)
 82→
 83→	var policyMatches []model.PolicyMatch
 84→	for _, m := range matches {
 85→		explanation := ""
 86→		if m.rule.Description != nil {
 87→			explanation = *m.rule.Description
 88→		}
 89→		policyMatches = append(policyMatches, model.PolicyMatch{
 90→			PolicyID:      m.policy.PolicyId,
 91→			PolicyVersion: m.policy.Version,
 92→			RuleID:        m.rule.RuleId,
 93→			Explanation:   explanation,
 94→		})
 95→	}
 96→
 97→	decision := model.Decision{
 98→		Disposition:     disposition,
 99→		RiskLevel:       riskLevel,
100→		MatchedPolicies: policyMatches,

  1→// Package aileron provides a Go client for the Aileron control plane API.
  2→//
  3→// Usage:
  4→//
  5→//	client := aileron.NewClient("https://api.example.com", aileron.WithAPIKey("..."))
  6→//	intent, err := client.Intents.Create(ctx, aileron.CreateIntentRequest{ ... })
  7→package aileron
  8→
  9→import (
 10→	"bytes"
 11→	"context"
 12→	"encoding/json"
 13→	"fmt"
 14→	"io"
 15→	"net/http"
 16→	"time"
 17→)
 18→
 19→// Client is the Aileron API client.
 20→type Client struct {
 21→	baseURL    string
 22→	httpClient *http.Client
 23→	apiKey     string
 24→
 25→	Intents    *IntentsService
 26→	Approvals  *ApprovalsService
 27→	Policies   *PoliciesService
 28→	Executions *ExecutionsService
 29→}
 30→
 31→// Option configures the client.
 32→type Option func(*Client)
 33→
 34→// WithAPIKey sets the API key for authentication.
 35→func WithAPIKey(key string) Option {
 36→	return func(c *Client) {
 37→		c.apiKey = key
 38→	}
 39→}
 40→
 41→// WithHTTPClient sets a custom HTTP client.
 42→func WithHTTPClient(hc *http.Client) Option {
 43→	return func(c *Client) {
 44→		c.httpClient = hc
 45→	}
 46→}
 47→
 48→// NewClient returns a new Aileron API client.
 49→func NewClient(baseURL string, opts ...Option) *Client {
 50→	c := &Client{
 51→		baseURL: baseURL,
 52→		httpClient: &http.Client{
 53→			Timeout: 30 * time.Second,
 54→		},
 55→	}
 56→	for _, opt := range opts {
 57→		opt(c)
 58→	}
 59→
 60→	c.Intents = &IntentsService{client: c}
 61→	c.Approvals = &ApprovalsService{client: c}
 62→	c.Policies = &PoliciesService{client: c}
 63→	c.Executions = &ExecutionsService{client: c}
 64→
 65→	return c
 66→}
 67→
 68→func (c *Client) do(ctx context.Context, method, path string, body, result any) error {
 69→	var bodyReader io.Reader
 70→	if body != nil {
 71→		data, err := json.Marshal(body)
 72→		if err != nil {
 73→			return fmt.Errorf("marshal request: %w", err)
 74→		}
 75→		bodyReader = bytes.NewReader(data)
 76→	}
 77→
 78→	req, err := http.NewRequestWithContext(ctx, method, c.baseURL+path, bodyReader)
 79→	if err != nil {
 80→		return fmt.Errorf("create request: %w", err)
 81→	}
 82→	req.Header.Set("Content-Type", "application/json")
 83→	if c.apiKey != "" {
 84→		req.Header.Set("Authorization", "Bearer "+c.apiKey)
 85→	}
 86→
 87→	resp, err := c.httpClient.Do(req)
 88→	if err != nil {
 89→		return fmt.Errorf("http request: %w", err)
 90→	}
 91→	defer resp.Body.Close()
 92→
 93→	respBody, err := io.ReadAll(resp.Body)
 94→	if err != nil {
 95→		return fmt.Errorf("read response: %w", err)
 96→	}
 97→
 98→	if resp.StatusCode >= 400 {
 99→		return fmt.Errorf("API error %d: %s", resp.StatusCode, string(respBody))
100→	}

100→	}
101→
102→	if result != nil && len(respBody) > 0 {
103→		if err := json.Unmarshal(respBody, result); err != nil {
104→			return fmt.Errorf("unmarshal response: %w", err)
105→		}
106→	}
107→	return nil
108→}
