  1→package policy
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"sort"
  8→	"strings"
  9→
 10→	api "github.com/ALRubinger/aileron/core/api/gen"
 11→	"github.com/ALRubinger/aileron/core/model"
 12→	"github.com/ALRubinger/aileron/core/store"
 13→)
 14→
 15→// RuleEngine evaluates policy rules from the policy store against intents.
 16→type RuleEngine struct {
 17→	policies store.PolicyStore
 18→}
 19→
 20→// NewRuleEngine returns a policy engine backed by the given store.
 21→func NewRuleEngine(policies store.PolicyStore) *RuleEngine {
 22→	return &RuleEngine{policies: policies}
 23→}
 24→
 25→// Evaluate implements Engine.
 26→func (e *RuleEngine) Evaluate(ctx context.Context, req EvaluationRequest) (model.Decision, error) {
 27→	// Load all active policies for the workspace.
 28→	activeStatus := api.PolicyStatusActive
 29→	policies, err := e.policies.List(ctx, store.PolicyFilter{
 30→		WorkspaceID: req.WorkspaceID,
 31→		Status:      &activeStatus,
 32→	})
 33→	if err != nil {
 34→		return model.Decision{}, fmt.Errorf("policy: list policies: %w", err)
 35→	}
 36→
 37→	// Flatten to intent fields for condition evaluation.
 38→	fields := flattenIntent(req.Action, req.Context)
 39→
 40→	// Collect all matching rules across policies, sorted by priority.
 41→	type match struct {
 42→		policy api.Policy
 43→		rule   api.PolicyRule
 44→	}
 45→	var matches []match
 46→
 47→	for _, p := range policies {
 48→		for _, r := range p.Rules {
 49→			if !actionTypeMatches(req.Action.Type, r) {
 50→				continue
 51→			}
 52→			if !conditionsMatch(r.Conditions, fields) {
 53→				continue
 54→			}
 55→			matches = append(matches, match{policy: p, rule: r})
 56→		}
 57→	}
 58→
 59→	if len(matches) == 0 {
 60→		// Default: allow with low risk when no rules match.
 61→		return model.Decision{
 62→			Disposition: model.DispositionAllow,
 63→			RiskLevel:   model.RiskLevelLow,
 64→		}, nil
 65→	}
 66→
 67→	// Sort by priority descending (higher priority wins).
 68→	sort.Slice(matches, func(i, j int) bool {
 69→		pi, pj := 0, 0
 70→		if matches[i].rule.Priority != nil {
 71→			pi = *matches[i].rule.Priority
 72→		}
 73→		if matches[j].rule.Priority != nil {
 74→			pj = *matches[j].rule.Priority
 75→		}
 76→		return pi > pj
 77→	})
 78→
 79→	winner := matches[0]
 80→	disposition := effectToDisposition(winner.rule.Effect)
 81→	riskLevel := effectToRiskLevel(winner.rule.Effect)
 82→
 83→	var policyMatches []model.PolicyMatch
 84→	for _, m := range matches {
 85→		explanation := ""
 86→		if m.rule.Description != nil {
 87→			explanation = *m.rule.Description
 88→		}
 89→		policyMatches = append(policyMatches, model.PolicyMatch{
 90→			PolicyID:      m.policy.PolicyId,
 91→			PolicyVersion: m.policy.Version,
 92→			RuleID:        m.rule.RuleId,
 93→			Explanation:   explanation,
 94→		})
 95→	}
 96→
 97→	decision := model.Decision{
 98→		Disposition:     disposition,
 99→		RiskLevel:       riskLevel,
100→		MatchedPolicies: policyMatches,
101→	}
102→
103→	if disposition == model.DispositionDeny {
104→		reason := "denied by policy"
105→		if winner.rule.Description != nil {
106→			reason = *winner.rule.Description
107→		}
108→		decision.DenialReason = reason
109→	}
110→
111→	return decision, nil
112→}
113→
114→// actionTypeMatches checks whether a rule applies to the given action type.
115→// Rules without conditions that have a field matching "action.type" apply to
116→// all action types. Rules with action.type conditions are filtered later.
117→// For now, we check conditions for an "action.type" field match.
118→func actionTypeMatches(actionType string, rule api.PolicyRule) bool {
119→	if rule.Conditions == nil || len(*rule.Conditions) == 0 {
120→		return true // no conditions = matches all
121→	}
122→	for _, c := range *rule.Conditions {
123→		if c.Field != nil && *c.Field == "action.type" {
124→			return evaluateCondition(c, actionType)
125→		}
126→	}
127→	// No action.type condition — rule matches all action types.
128→	return true
129→}
130→
131→// conditionsMatch checks all conditions in a rule against flattened intent fields.
132→func conditionsMatch(conditions *[]api.PolicyCondition, fields map[string]any) bool {
133→	if conditions == nil {
134→		return true
135→	}
136→	for _, c := range *conditions {
137→		if c.Field == nil || c.Operator == nil || c.Value == nil {
138→			continue
139→		}
140→		fieldVal, ok := fields[*c.Field]
141→		if !ok {
142→			// Field not present in intent — condition fails.
143→			return false
144→		}
145→		if !evaluateCondition(c, fieldVal) {
146→			return false
147→		}
148→	}
149→	return true
150→}
151→
152→// evaluateCondition evaluates a single condition against a field value.
153→func evaluateCondition(c api.PolicyCondition, fieldVal any) bool {
154→	if c.Operator == nil || c.Value == nil {
155→		return true
156→	}
157→
158→	condVal := extractConditionValue(c.Value)
159→	fieldStr := fmt.Sprintf("%v", fieldVal)
160→
161→	switch *c.Operator {
162→	case api.Eq:
163→		return fieldStr == fmt.Sprintf("%v", condVal)
164→	case api.Neq:
165→		return fieldStr != fmt.Sprintf("%v", condVal)
166→	case api.In:
167→		return valueInList(fieldStr, condVal)
168→	case api.NotIn:
169→		return !valueInList(fieldStr, condVal)
170→	case api.Contains:
171→		return strings.Contains(fieldStr, fmt.Sprintf("%v", condVal))
172→	case api.Matches:
173→		// Simple glob matching with * wildcard.
174→		pattern := fmt.Sprintf("%v", condVal)
175→		return globMatch(pattern, fieldStr)
176→	case api.Gt, api.Gte, api.Lt, api.Lte:
177→		return compareNumeric(*c.Operator, fieldVal, condVal)
178→	default:
179→		return false
180→	}
181→}
182→
183→// extractConditionValue pulls the actual value from the union type.
184→func extractConditionValue(v *api.PolicyCondition_Value) any {
185→	if v == nil {
186→		return nil
187→	}
188→	// Try string first (most common).
189→	if s, err := v.AsPolicyConditionValue0(); err == nil {
190→		return s
191→	}
192→	// Try array (for in/not_in).
193→	if arr, err := v.AsPolicyConditionValue4(); err == nil {
194→		return arr
195→	}
196→	// Try int.
197→	if i, err := v.AsPolicyConditionValue2(); err == nil {
198→		return i
199→	}
200→	// Try float.
201→	if f, err := v.AsPolicyConditionValue1(); err == nil {
202→		return f
203→	}
204→	// Try bool.
205→	if b, err := v.AsPolicyConditionValue3(); err == nil {
206→		return b
207→	}
208→	// Fallback: unmarshal as raw JSON.
209→	data, _ := v.MarshalJSON()
210→	var raw any
211→	json.Unmarshal(data, &raw)
212→	return raw
213→}
214→
215→func valueInList(val string, list any) bool {
216→	switch l := list.(type) {
217→	case []interface{}:
218→		for _, item := range l {
219→			if fmt.Sprintf("%v", item) == val {
220→				return true
221→			}
222→		}
223→	case []string:
224→		for _, item := range l {
225→			if item == val {
226→				return true
227→			}
228→		}
229→	}
230→	return false
231→}
232→
233→func globMatch(pattern, value string) bool {
234→	// Simple wildcard matching: * matches any substring.
235→	if pattern == "*" {
236→		return true
237→	}
238→	if strings.HasSuffix(pattern, ".*") {
239→		prefix := strings.TrimSuffix(pattern, ".*")
240→		return strings.HasPrefix(value, prefix+".")
241→	}
242→	if strings.HasPrefix(pattern, "*") {
243→		return strings.HasSuffix(value, pattern[1:])
244→	}
245→	return pattern == value
246→}
247→
248→func compareNumeric(op api.PolicyConditionOperator, fieldVal, condVal any) bool {
249→	fv := toFloat64(fieldVal)
250→	cv := toFloat64(condVal)
251→	switch op {
252→	case api.Gt:
253→		return fv > cv
254→	case api.Gte:
255→		return fv >= cv
256→	case api.Lt:
257→		return fv < cv
258→	case api.Lte:
259→		return fv <= cv
260→	}
261→	return false
262→}
263→
264→func toFloat64(v any) float64 {
265→	switch n := v.(type) {
266→	case int:
267→		return float64(n)
268→	case int64:
269→		return float64(n)
270→	case float32:
271→		return float64(n)
272→	case float64:
273→		return n
274→	case json.Number:
275→		f, _ := n.Float64()
276→		return f
277→	}
278→	return 0
279→}
