  1→// Package github implements the git connector for GitHub.
  2→//
  3→// This connector executes git.pull_request.* and git.commit.* actions via
  4→// the GitHub REST API. Credentials (personal access token or GitHub App
  5→// installation token) are injected at execution time from the vault.
  6→package github
  7→
  8→import (
  9→	"bytes"
 10→	"context"
 11→	"encoding/json"
 12→	"errors"
 13→	"fmt"
 14→	"io"
 15→	"net/http"
 16→	"strings"
 17→
 18→	"github.com/ALRubinger/aileron/core/connector"
 19→)
 20→
 21→const (
 22→	connectorType     = "git"
 23→	connectorProvider = "github"
 24→	githubAPI         = "https://api.github.com"
 25→)
 26→
 27→// Connector executes git actions via GitHub.
 28→type Connector struct{}
 29→
 30→// New returns a new GitHub connector.
 31→func New() *Connector {
 32→	return &Connector{}
 33→}
 34→
 35→// Type implements connector.Connector.
 36→func (c *Connector) Type() string { return connectorType }
 37→
 38→// Provider implements connector.Connector.
 39→func (c *Connector) Provider() string { return connectorProvider }
 40→
 41→// Execute implements connector.Connector.
 42→func (c *Connector) Execute(ctx context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
 43→	if req.Credential == nil {
 44→		return connector.ExecutionResult{}, errors.New("github: no credential injected")
 45→	}
 46→
 47→	switch req.ActionType {
 48→	case "git.pull_request.create":
 49→		return c.createPullRequest(ctx, req)
 50→	case "git.pull_request.merge":
 51→		return c.mergePullRequest(ctx, req)
 52→	case "git.pull_request.close":
 53→		return c.closePullRequest(ctx, req)
 54→	default:
 55→		return connector.ExecutionResult{
 56→			Status: connector.ExecutionStatusFailed,
 57→			Error:  "github: unsupported action type: " + req.ActionType,
 58→		}, nil
 59→	}
 60→}
 61→
 62→func (c *Connector) createPullRequest(ctx context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
 63→	repo := paramStr(req.Parameters, "repository")
 64→	if repo == "" {
 65→		return failResult("github: repository parameter required"), nil
 66→	}
 67→	head := paramStr(req.Parameters, "branch")
 68→	base := paramStr(req.Parameters, "base_branch")
 69→	title := paramStr(req.Parameters, "pr_title")
 70→	body := paramStr(req.Parameters, "pr_body")
 71→
 72→	if head == "" || base == "" || title == "" {
 73→		return failResult("github: branch, base_branch, and pr_title parameters required"), nil
 74→	}
 75→
 76→	payload := map[string]interface{}{
 77→		"title": title,
 78→		"head":  head,
 79→		"base":  base,
 80→	}
 81→	if body != "" {
 82→		payload["body"] = body
 83→	}
 84→
 85→	url := fmt.Sprintf("%s/repos/%s/pulls", githubAPI, repo)
 86→	result, err := githubPost(ctx, url, string(req.Credential.Value), payload)
 87→	if err != nil {
 88→		return failResult("github: " + err.Error()), nil
 89→	}
 90→
 91→	prURL, _ := result["html_url"].(string)
 92→	prNumber, _ := result["number"].(float64)
 93→
 94→	return connector.ExecutionResult{
 95→		Status:     connector.ExecutionStatusSucceeded,
 96→		ReceiptRef: prURL,
 97→		Output: map[string]any{
 98→			"pr_url":    prURL,
 99→			"pr_number": int(prNumber),
100→		},
101→	}, nil
102→}
103→
104→func (c *Connector) mergePullRequest(ctx context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
105→	repo := paramStr(req.Parameters, "repository")
106→	prNumber := paramStr(req.Parameters, "pr_number")
107→	if repo == "" || prNumber == "" {
108→		return failResult("github: repository and pr_number parameters required"), nil
109→	}
110→
111→	url := fmt.Sprintf("%s/repos/%s/pulls/%s/merge", githubAPI, repo, prNumber)
112→	_, err := githubPut(ctx, url, string(req.Credential.Value), map[string]interface{}{})
113→	if err != nil {
114→		return failResult("github: " + err.Error()), nil
115→	}
116→
117→	return connector.ExecutionResult{
118→		Status: connector.ExecutionStatusSucceeded,
119→		Output: map[string]any{"merged": true},
120→	}, nil
121→}
122→
123→func (c *Connector) closePullRequest(ctx context.Context, req connector.ExecutionRequest) (connector.ExecutionResult, error) {
124→	repo := paramStr(req.Parameters, "repository")
125→	prNumber := paramStr(req.Parameters, "pr_number")
126→	if repo == "" || prNumber == "" {
127→		return failResult("github: repository and pr_number parameters required"), nil
128→	}
129→
130→	url := fmt.Sprintf("%s/repos/%s/pulls/%s", githubAPI, repo, prNumber)
131→	_, err := githubPatch(ctx, url, string(req.Credential.Value), map[string]interface{}{
132→		"state": "closed",
133→	})
134→	if err != nil {
135→		return failResult("github: " + err.Error()), nil
136→	}
137→
138→	return connector.ExecutionResult{
139→		Status: connector.ExecutionStatusSucceeded,
140→		Output: map[string]any{"closed": true},
141→	}, nil
142→}
143→
144→// --- HTTP helpers ---
145→
146→func githubPost(ctx context.Context, url, token string, payload map[string]interface{}) (map[string]interface{}, error) {
147→	return githubRequest(ctx, http.MethodPost, url, token, payload)
148→}
149→
150→func githubPut(ctx context.Context, url, token string, payload map[string]interface{}) (map[string]interface{}, error) {
151→	return githubRequest(ctx, http.MethodPut, url, token, payload)
152→}
153→
154→func githubPatch(ctx context.Context, url, token string, payload map[string]interface{}) (map[string]interface{}, error) {
155→	return githubRequest(ctx, http.MethodPatch, url, token, payload)
156→}
157→
158→func githubRequest(ctx context.Context, method, url, token string, payload map[string]interface{}) (map[string]interface{}, error) {
159→	body, err := json.Marshal(payload)
160→	if err != nil {
161→		return nil, fmt.Errorf("marshal payload: %w", err)
162→	}
163→
164→	req, err := http.NewRequestWithContext(ctx, method, url, bytes.NewReader(body))
165→	if err != nil {
166→		return nil, fmt.Errorf("create request: %w", err)
167→	}
168→
169→	token = strings.TrimSpace(token)
170→	req.Header.Set("Authorization", "Bearer "+token)
171→	req.Header.Set("Accept", "application/vnd.github+json")
172→	req.Header.Set("Content-Type", "application/json")
173→	req.Header.Set("X-GitHub-Api-Version", "2022-11-28")
174→
175→	resp, err := http.DefaultClient.Do(req)
176→	if err != nil {
177→		return nil, fmt.Errorf("http request: %w", err)
178→	}
179→	defer resp.Body.Close()
180→
181→	respBody, err := io.ReadAll(resp.Body)
182→	if err != nil {
183→		return nil, fmt.Errorf("read response: %w", err)
184→	}
185→
186→	if resp.StatusCode >= 400 {
187→		return nil, fmt.Errorf("API error %d: %s", resp.StatusCode, string(respBody))
188→	}
189→
190→	var result map[string]interface{}
191→	if len(respBody) > 0 {
192→		if err := json.Unmarshal(respBody, &result); err != nil {
193→			return nil, fmt.Errorf("unmarshal response: %w", err)
194→		}
195→	}
196→	return result, nil
197→}
198→
199→func paramStr(params map[string]any, key string) string {
200→	v, ok := params[key]
201→	if !ok {
202→		return ""
203→	}
204→	s, ok := v.(string)
205→	if !ok {
206→		return fmt.Sprintf("%v", v)
207→	}
208→	return s
209→}
210→
211→func failResult(msg string) connector.ExecutionResult {
212→	return connector.ExecutionResult{
213→		Status: connector.ExecutionStatusFailed,
214→		Error:  msg,
215→	}
216→}
