409→func (s *server) listPendingApprovals(ctx context.Context, args map[string]any) toolResult {
410→	workspaceID := argStr(args, "workspace_id")
411→	if workspaceID == "" {
412→		workspaceID = "default"
413→	}
414→
415→	resp, err := s.client.Approvals.List(ctx, workspaceID)
416→	if err != nil {
417→		return errorResult("Failed to list approvals: " + err.Error())
418→	}
419→
420→	var pending []map[string]any
421→	for _, a := range resp.Items {
422→		if a.Status == "pending" {
423→			entry := map[string]any{
424→				"approval_id": a.ApprovalID,
