// Package mcpclient provides a Go client that speaks Model Context Protocol (MCP)
// over stdio to downstream MCP servers running as subprocesses.
//
// Communication uses newline-delimited JSON-RPC 2.0 over the subprocess's
// stdin (requests) and stdout (responses).
package mcpclient

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"os/exec"
	"sync"
	"sync/atomic"
	"syscall"
	"time"
)

// ToolDef describes a tool exposed by a downstream MCP server.
type ToolDef struct {
	Name        string         `json:"name"`
	Description string         `json:"description"`
	InputSchema map[string]any `json:"inputSchema"`
}

// ToolResult is the result from a tools/call invocation.
type ToolResult struct {
	Content []ToolContent `json:"content"`
	IsError bool          `json:"isError,omitempty"`
}

// ToolContent represents a single content block within a tool result.
type ToolContent struct {
	Type string `json:"type"`
	Text string `json:"text"`
}

// Client manages a connection to a single downstream MCP server subprocess.
type Client struct {
	name   string
	cmd    *exec.Cmd
	stdin  io.WriteCloser
	stdout *bufio.Reader
	mu     sync.Mutex // protects writes to stdin and reads from stdout
	tools  []ToolDef
	nextID int64
}

// JSON-RPC 2.0 wire types (internal).

type jsonrpcRequest struct {
	JSONRPC string `json:"jsonrpc"`
	ID      any    `json:"id,omitempty"`
	Method  string `json:"method"`
	Params  any    `json:"params,omitempty"`
}

type jsonrpcResponse struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      json.RawMessage `json:"id,omitempty"`
	Result  json.RawMessage `json:"result,omitempty"`
	Error   *jsonrpcError   `json:"error,omitempty"`
}

type jsonrpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

func (e *jsonrpcError) Error() string {
	return fmt.Sprintf("jsonrpc error %d: %s", e.Code, e.Message)
}

// NewClient spawns a downstream MCP server as a subprocess and performs the
// MCP initialize handshake. The command slice must contain at least the
// program name; additional elements are passed as arguments. The env slice
// is merged with os.Environ() so the subprocess inherits the current
// environment plus any overrides.
func NewClient(ctx context.Context, name string, command []string, env []string) (*Client, error) {
	if len(command) == 0 {
		return nil, fmt.Errorf("mcpclient: command must not be empty")
	}

	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
	cmd.Env = append(os.Environ(), env...)
	cmd.Stderr = os.Stderr

	stdinPipe, err := cmd.StdinPipe()
	if err != nil {
		return nil, fmt.Errorf("mcpclient: stdin pipe: %w", err)
	}

	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		return nil, fmt.Errorf("mcpclient: stdout pipe: %w", err)
	}

	if err := cmd.Start(); err != nil {
		return nil, fmt.Errorf("mcpclient: start %q: %w", command[0], err)
	}

	c := &Client{
		name:   name,
		cmd:    cmd,
		stdin:  stdinPipe,
		stdout: bufio.NewReader(stdoutPipe),
		nextID: 1, // 1 is reserved for the initialize request
	}

	// --- MCP initialize handshake ---

	initParams := map[string]any{
		"protocolVersion": "2024-11-05",
		"capabilities":    map[string]any{},
		"clientInfo": map[string]any{
			"name":    "aileron-gateway",
			"version": "0.0.1",
		},
	}

	_, err = c.sendRequest("initialize", initParams)
	if err != nil {
		// Best-effort cleanup on failure.
		_ = c.Close()
		return nil, fmt.Errorf("mcpclient: initialize handshake: %w", err)
	}

	// Send the initialized notification (no ID — it's a notification).
	if err := c.sendNotification("notifications/initialized"); err != nil {
		_ = c.Close()
		return nil, fmt.Errorf("mcpclient: initialized notification: %w", err)
	}

	// Discover available tools.
	if _, err := c.DiscoverTools(ctx); err != nil {
		_ = c.Close()
		return nil, fmt.Errorf("mcpclient: discover tools: %w", err)
	}

	return c, nil
}

// DiscoverTools sends a tools/list request and caches the result.
func (c *Client) DiscoverTools(_ context.Context) ([]ToolDef, error) {
	raw, err := c.sendRequest("tools/list", nil)
	if err != nil {
		return nil, err
	}

	var envelope struct {
		Tools []ToolDef `json:"tools"`
	}
	if err := json.Unmarshal(raw, &envelope); err != nil {
		return nil, fmt.Errorf("mcpclient: parse tools/list result: %w", err)
	}

	c.tools = envelope.Tools
	return c.tools, nil
}

// CallTool invokes a tool on the downstream MCP server by name.
func (c *Client) CallTool(_ context.Context, name string, arguments map[string]any) (*ToolResult, error) {
	params := map[string]any{
		"name":      name,
		"arguments": arguments,
	}

	raw, err := c.sendRequest("tools/call", params)
	if err != nil {
		return nil, err
	}

	var result ToolResult
	if err := json.Unmarshal(raw, &result); err != nil {
		return nil, fmt.Errorf("mcpclient: parse tools/call result: %w", err)
	}

	return &result, nil
}

// Tools returns the cached list of tools discovered from the server.
func (c *Client) Tools() []ToolDef {
	return c.tools
}

// Name returns the human-readable name of this client connection.
func (c *Client) Name() string {
	return c.name
}

// Close terminates the subprocess. It sends SIGTERM first, then SIGKILL
// after a 5-second timeout if the process hasn't exited.
func (c *Client) Close() error {
	if c.cmd == nil || c.cmd.Process == nil {
		return nil
	}

	// Close stdin so the subprocess sees EOF.
	_ = c.stdin.Close()

	// Send SIGTERM.
	if err := c.cmd.Process.Signal(syscall.SIGTERM); err != nil {
		// Process may have already exited; just wait.
		_ = c.cmd.Wait()
		return nil
	}

	// Wait up to 5 seconds for graceful exit.
	done := make(chan error, 1)
	go func() {
		done <- c.cmd.Wait()
	}()

	select {
	case err := <-done:
		return err
	case <-time.After(5 * time.Second):
		_ = c.cmd.Process.Kill()
		return <-done
	}
}

// nextRequestID returns a monotonically increasing request ID.
func (c *Client) nextRequestID() int64 {
	return atomic.AddInt64(&c.nextID, 1)
}

// sendRequest sends a JSON-RPC request and waits for the corresponding
// response. It returns the raw "result" field on success.
func (c *Client) sendRequest(method string, params any) (json.RawMessage, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	id := c.nextRequestID()
	req := jsonrpcRequest{
		JSONRPC: "2.0",
		ID:      id,
		Method:  method,
		Params:  params,
	}

	data, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("mcpclient: marshal request: %w", err)
	}

	// Write newline-delimited JSON.
	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
		return nil, fmt.Errorf("mcpclient: write request: %w", err)
	}

	resp, err := c.readResponse()
	if err != nil {
		return nil, err
	}

	if resp.Error != nil {
		return nil, resp.Error
	}

	return resp.Result, nil
}

// sendNotification sends a JSON-RPC notification (no ID, no response expected).
func (c *Client) sendNotification(method string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	req := jsonrpcRequest{
		JSONRPC: "2.0",
		Method:  method,
	}

	data, err := json.Marshal(req)
	if err != nil {
		return fmt.Errorf("mcpclient: marshal notification: %w", err)
	}

	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
		return fmt.Errorf("mcpclient: write notification: %w", err)
	}

	return nil
}

// readResponse reads one newline-delimited JSON line from the subprocess
// stdout and parses it as a JSON-RPC response.
func (c *Client) readResponse() (*jsonrpcResponse, error) {
	line, err := c.stdout.ReadBytes('\n')
	if err != nil {
		return nil, fmt.Errorf("mcpclient: read response: %w", err)
	}

	var resp jsonrpcResponse
	if err := json.Unmarshal(line, &resp); err != nil {
		return nil, fmt.Errorf("mcpclient: parse response: %w (raw: %s)", err, string(line))
	}

	return &resp, nil
}

// Package config loads and validates YAML configuration for the Aileron
// MCP gateway.
//
// A configuration file defines the set of downstream MCP servers that
// Aileron proxies, along with optional policy mappings and environment
// variable overrides. Environment values prefixed with "vault://" are
// resolved from the Aileron vault at launch time via [ResolveVaultEnv].
package config

import (
	"fmt"
	"os"
	"regexp"

	"gopkg.in/yaml.v3"
)

// namePattern matches valid downstream server names: starts with a letter,
// followed by zero or more alphanumeric characters or underscores.
var namePattern = regexp.MustCompile(`^[a-zA-Z][a-zA-Z0-9_]*$`)

// vaultPrefix is the sentinel prefix for environment variable values that
// should be resolved from the vault.
const vaultPrefix = "vault://"

// Config is the top-level Aileron gateway configuration.
type Config struct {
	// Version is the config file format version. Currently "1".
	Version string `yaml:"version"`

	// WorkspaceID is the default workspace for policy evaluation.
	// Defaults to "default" if empty.
	WorkspaceID string `yaml:"workspace_id"`

	// DownstreamServers lists the MCP servers that Aileron proxies.
	DownstreamServers []DownstreamServer `yaml:"downstream_servers"`
}

// DownstreamServer defines a single downstream MCP server.
type DownstreamServer struct {
	// Name is a unique identifier for this server, used as tool name prefix.
	// Must be a valid identifier (alphanumeric + underscore, no spaces).
	Name string `yaml:"name"`

	// Command is the command to execute, including any arguments.
	// Example: ["npx", "-y", "@modelcontextprotocol/server-github"]
	Command []string `yaml:"command"`

	// Env is environment variables to set for the subprocess.
	// Values prefixed with "vault://" are resolved from the Aileron vault at launch time.
	Env map[string]string `yaml:"env"`

	// PolicyMapping configures how this server's tools map to policy evaluation.
	PolicyMapping *PolicyMapping `yaml:"policy_mapping,omitempty"`
}

// PolicyMapping configures how tools from a downstream server map to the
// policy engine's action type namespace.
type PolicyMapping struct {
	// ToolPrefix maps tool calls to the action type namespace.
	// For example, with tool_prefix "git", a tool "create_pull_request"
	// becomes action type "git.create_pull_request" for policy evaluation.
	ToolPrefix string `yaml:"tool_prefix"`
}

// Load reads a YAML configuration file from path, unmarshals it, and
// validates the result. It returns the parsed Config or the first error
// encountered.
func Load(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading config file: %w", err)
	}

	var cfg Config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing config file: %w", err)
	}

	if err := cfg.Validate(); err != nil {
		return nil, err
	}

	return &cfg, nil
}

// LoadFromEnvOrDefault loads configuration using the following precedence:
//
//  1. The path in the AILERON_CONFIG environment variable.
//  2. "aileron.yaml" in the current working directory.
//  3. An empty Config (no downstream servers) — this is not an error; it
//     allows the gateway to start with no downstream servers configured.
func LoadFromEnvOrDefault() (*Config, error) {
	if path := os.Getenv("AILERON_CONFIG"); path != "" {
		return Load(path)
	}

	const defaultFile = "aileron.yaml"
	if _, err := os.Stat(defaultFile); err == nil {
		return Load(defaultFile)
	}

	return &Config{}, nil
}

// Validate checks the configuration for structural correctness. It returns
// a descriptive error for the first validation failure found.
func (c *Config) Validate() error {
	if c.Version != "" && c.Version != "1" {
		return fmt.Errorf("unsupported config version %q: must be \"1\"", c.Version)
	}

	seen := make(map[string]bool, len(c.DownstreamServers))
	for i, ds := range c.DownstreamServers {
		if ds.Name == "" {
			return fmt.Errorf("downstream_servers[%d]: name must not be empty", i)
		}
		if !namePattern.MatchString(ds.Name) {
			return fmt.Errorf("downstream_servers[%d]: name %q must match %s", i, ds.Name, namePattern.String())
		}
		if seen[ds.Name] {
			return fmt.Errorf("downstream_servers[%d]: duplicate name %q", i, ds.Name)
		}
		seen[ds.Name] = true

		if len(ds.Command) == 0 {
			return fmt.Errorf("downstream_servers[%d] (%s): command must not be empty", i, ds.Name)
		}
	}

	return nil
}

// ResolveVaultEnv returns a copy of env with all "vault://"-prefixed values
// resolved through the provided vaultGet function. Non-vault values are
// copied unchanged. The original map is never modified.
func ResolveVaultEnv(env map[string]string, vaultGet func(path string) ([]byte, error)) (map[string]string, error) {
	resolved := make(map[string]string, len(env))

	for k, v := range env {
		if len(v) > len(vaultPrefix) && v[:len(vaultPrefix)] == vaultPrefix {
			vaultPath := v[len(vaultPrefix):]
			secret, err := vaultGet(vaultPath)
			if err != nil {
				return nil, fmt.Errorf("resolving vault env %q (path %q): %w", k, vaultPath, err)
			}
			resolved[k] = string(secret)
		} else {
			resolved[k] = v
		}
	}

	return resolved, nil
}

