// Package main implements an MCP (Model Context Protocol) server that exposes
// the Aileron control plane as tools callable by Claude Code and other MCP clients.
//
// It communicates over stdio using JSON-RPC 2.0, per the MCP specification.
//
// Modes:
//   - Embedded (default): runs an in-process Aileron server with in-memory stores.
//   - Remote: set AILERON_API_URL to connect to an existing Aileron server.
package main

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net"
	"net/http"
	"os"

	"github.com/ALRubinger/aileron/core/app"
	aileron "github.com/ALRubinger/aileron/sdk/go"
)

// --- JSON-RPC types ---

type jsonrpcRequest struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      json.RawMessage `json:"id,omitempty"`
	Method  string          `json:"method"`
	Params  json.RawMessage `json:"params,omitempty"`
}

type jsonrpcResponse struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      json.RawMessage `json:"id,omitempty"`
	Result  any             `json:"result,omitempty"`
	Error   *jsonrpcError   `json:"error,omitempty"`
}

type jsonrpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

// --- MCP types ---

type toolDef struct {
	Name        string    `json:"name"`
	Description string    `json:"description"`
	InputSchema schema    `json:"inputSchema"`
}

type schema struct {
	Type       string                `json:"type"`
	Properties map[string]schemaProp `json:"properties,omitempty"`
	Required   []string              `json:"required,omitempty"`
}

type schemaProp struct {
	Type        string `json:"type"`
	Description string `json:"description"`
}

type callToolParams struct {
	Name      string         `json:"name"`
	Arguments map[string]any `json:"arguments"`
}

type toolResult struct {
	Content []toolContent `json:"content"`
	IsError bool          `json:"isError,omitempty"`
}

type toolContent struct {
	Type string `json:"type"`
	Text string `json:"text"`
}

// --- Server ---

type server struct {
	client *aileron.Client
}

func main() {
	apiURL := os.Getenv("AILERON_API_URL")

	if apiURL == "" {
		// Embedded mode: start an in-process Aileron server on a random port.
		log := slog.New(slog.NewJSONHandler(io.Discard, nil))
		handler, err := app.NewHandler(log)
		if err != nil {
			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to start embedded server: %v\n", err)
			os.Exit(1)
		}
		listener, err := net.Listen("tcp", "127.0.0.1:0")
		if err != nil {
			fmt.Fprintf(os.Stderr, "aileron-mcp: failed to listen: %v\n", err)
			os.Exit(1)
		}
		go http.Serve(listener, handler)
		apiURL = "http://" + listener.Addr().String()
	}

	apiKey := os.Getenv("AILERON_API_KEY")
	client := aileron.NewClient(apiURL, aileron.WithAPIKey(apiKey))
	s := &server{client: client}

	scanner := bufio.NewScanner(os.Stdin)
	// Increase buffer size for large messages.
	scanner.Buffer(make([]byte, 0, 1024*1024), 1024*1024)

	for scanner.Scan() {
		line := scanner.Bytes()
		if len(line) == 0 {
			continue
		}

		var req jsonrpcRequest
		if err := json.Unmarshal(line, &req); err != nil {
			continue
		}

		resp := s.handle(req)
		if resp != nil {
			data, _ := json.Marshal(resp)
			fmt.Fprintf(os.Stdout, "%s\n", data)
		}
	}
}

func (s *server) handle(req jsonrpcRequest) *jsonrpcResponse {
	switch req.Method {
	case "initialize":
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result: map[string]any{
				"protocolVersion": "2024-11-05",
				"capabilities": map[string]any{
					"tools": map[string]any{},
				},
				"serverInfo": map[string]any{
					"name":    "aileron",
					"version": "0.0.1",
				},
			},
		}

	case "notifications/initialized":
		return nil // no response for notifications

	case "tools/list":
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result: map[string]any{
				"tools": s.tools(),
			},
		}

	case "tools/call":
		var params callToolParams
		if err := json.Unmarshal(req.Params, &params); err != nil {
			return errorResponse(req.ID, -32602, "invalid params: "+err.Error())
		}
		result := s.callTool(params)
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result:  result,
		}

	case "ping":
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      req.ID,
			Result:  map[string]any{},
		}

	default:
		return errorResponse(req.ID, -32601, "method not found: "+req.Method)
	}
}

func (s *server) tools() []toolDef {
	return []toolDef{
		{
			Name:        "submit_intent",
			Description: "Submit an action intent to the Aileron control plane for policy evaluation. Returns the disposition (allow/deny/require_approval) and any grant or approval IDs.",
			InputSchema: schema{
				Type: "object",
				Properties: map[string]schemaProp{
					"action_type":  {Type: "string", Description: "Dot-namespaced action type, e.g. 'git.pull_request.create', 'payment.charge'"},
					"summary":      {Type: "string", Description: "Human-readable summary of what the agent wants to do"},
					"justification": {Type: "string", Description: "Why this action is needed"},
					"repository":   {Type: "string", Description: "For git actions: owner/repo (e.g. 'acme/checkout')"},
					"branch":       {Type: "string", Description: "For git actions: source/head branch"},
					"base_branch":  {Type: "string", Description: "For git actions: target/base branch"},
					"pr_title":     {Type: "string", Description: "For git PR actions: pull request title"},
					"pr_body":      {Type: "string", Description: "For git PR actions: pull request body"},
					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
				},
				Required: []string{"action_type", "summary"},
			},
		},
		{
			Name:        "check_approval",
			Description: "Check the status of a pending approval request. Returns the current status and, if approved, the execution grant ID.",
			InputSchema: schema{
				Type: "object",
				Properties: map[string]schemaProp{
					"approval_id": {Type: "string", Description: "The approval ID to check"},
				},
				Required: []string{"approval_id"},
			},
		},
		{
			Name:        "execute_action",
			Description: "Execute an approved action using an execution grant. The grant must be active and not expired.",
			InputSchema: schema{
				Type: "object",
				Properties: map[string]schemaProp{
					"grant_id": {Type: "string", Description: "The execution grant ID"},
				},
				Required: []string{"grant_id"},
			},
		},
		{
			Name:        "list_pending_approvals",
			Description: "List all pending approval requests in the workspace.",
			InputSchema: schema{
				Type: "object",
				Properties: map[string]schemaProp{
					"workspace_id": {Type: "string", Description: "Workspace ID (default: 'default')"},
				},
			},
		},
	}
}

func (s *server) callTool(params callToolParams) toolResult {
	ctx := context.Background()

	switch params.Name {
	case "submit_intent":
		return s.submitIntent(ctx, params.Arguments)
	case "check_approval":
		return s.checkApproval(ctx, params.Arguments)
	case "execute_action":
		return s.executeAction(ctx, params.Arguments)
	case "list_pending_approvals":
		return s.listPendingApprovals(ctx, params.Arguments)
	default:
		return toolResult{
			Content: []toolContent{{Type: "text", Text: "Unknown tool: " + params.Name}},
			IsError: true,
		}
	}
}

func (s *server) submitIntent(ctx context.Context, args map[string]any) toolResult {
	actionType := argStr(args, "action_type")
	summary := argStr(args, "summary")
	workspaceID := argStr(args, "workspace_id")
	if workspaceID == "" {
		workspaceID = "default"
	}

	req := aileron.CreateIntentRequest{
		WorkspaceID:    workspaceID,
		AgentID:        "claude_code",
		IdempotencyKey: fmt.Sprintf("mcp-%s-%d", actionType, os.Getpid()),
		Action: aileron.ActionIntent{
			Type:    actionType,
			Summary: summary,
		},
		Context: &aileron.IntentContext{
			SourcePlatform: strPtr("claude_code"),
			UserPresent:    boolPtr(true),
		},
	}

	if just := argStr(args, "justification"); just != "" {
		req.Action.Justification = &just
	}

	// Populate domain-specific fields.
	if repo := argStr(args, "repository"); repo != "" {
		branch := argStr(args, "branch")
		baseBranch := argStr(args, "base_branch")
		prTitle := argStr(args, "pr_title")
		prBody := argStr(args, "pr_body")
		provider := "github"
		req.Action.Domain = &aileron.DomainAction{
			Git: &aileron.GitAction{
				Provider:   &provider,
				Repository: &repo,
				Branch:     nilIfEmpty(branch),
				BaseBranch: nilIfEmpty(baseBranch),
				PRTitle:    nilIfEmpty(prTitle),
				PRBody:     nilIfEmpty(prBody),
			},
		}
	}

	intent, err := s.client.Intents.Create(ctx, req)
	if err != nil {
		return errorResult("Failed to submit intent: " + err.Error())
	}

	result := map[string]any{
		"intent_id":   intent.IntentID,
		"status":      intent.Status,
		"disposition": intent.Decision.Disposition,
		"risk_level":  intent.Decision.RiskLevel,
	}
	if intent.Decision.ApprovalID != nil {
		result["approval_id"] = *intent.Decision.ApprovalID
		result["message"] = fmt.Sprintf("This action requires approval. Approval ID: %s. The user can approve at the Aileron UI.", *intent.Decision.ApprovalID)
	}
	if intent.Decision.ExecutionGrantID != nil {
		result["grant_id"] = *intent.Decision.ExecutionGrantID
		result["message"] = "Action approved by policy. Use execute_action with the grant_id to proceed."
	}
	if intent.Decision.DenialReason != nil {
		result["denial_reason"] = *intent.Decision.DenialReason
		result["message"] = fmt.Sprintf("Action denied: %s", *intent.Decision.DenialReason)
	}

	return jsonResult(result)
}

func (s *server) checkApproval(ctx context.Context, args map[string]any) toolResult {
	approvalID := argStr(args, "approval_id")
	if approvalID == "" {
		return errorResult("approval_id is required")
	}

	approval, err := s.client.Approvals.Get(ctx, approvalID)
	if err != nil {
		return errorResult("Failed to get approval: " + err.Error())
	}

	result := map[string]any{
		"approval_id": approval.ApprovalID,
		"status":      approval.Status,
		"intent_id":   approval.IntentID,
	}

	switch approval.Status {
	case "approved":
		// Get the intent to find the grant ID.
		intent, err := s.client.Intents.Get(ctx, approval.IntentID)
		if err == nil && intent.Decision.ExecutionGrantID != nil {
			result["grant_id"] = *intent.Decision.ExecutionGrantID
			result["message"] = "Approved! Use execute_action with the grant_id to proceed."
		} else {
			result["message"] = "Approved, but grant ID not yet available."
		}
	case "denied":
		result["message"] = "The approval request was denied."
	case "pending":
		result["message"] = "Still waiting for human approval."
	default:
		result["message"] = "Approval status: " + approval.Status
	}

	return jsonResult(result)
}

func (s *server) executeAction(ctx context.Context, args map[string]any) toolResult {
	grantID := argStr(args, "grant_id")
	if grantID == "" {
		return errorResult("grant_id is required")
	}

	resp, err := s.client.Executions.Run(ctx, aileron.ExecutionRunRequest{
		GrantID: grantID,
	})
	if err != nil {
		return errorResult("Failed to execute: " + err.Error())
	}

	result := map[string]any{
		"execution_id": resp.ExecutionID,
		"status":       resp.Status,
		"message":      "Execution started. ID: " + resp.ExecutionID,
	}

	// Poll for completion (the execution may complete synchronously).
	exec, err := s.client.Executions.Get(ctx, resp.ExecutionID)
	if err == nil {
		result["status"] = exec.Status
		if exec.Output != nil {
			result["output"] = *exec.Output
		}
		if exec.ReceiptRef != nil {
			result["receipt_ref"] = *exec.ReceiptRef
			result["message"] = "Execution completed. Result: " + *exec.ReceiptRef
		}
	}

	return jsonResult(result)
}

func (s *server) listPendingApprovals(ctx context.Context, args map[string]any) toolResult {
	workspaceID := argStr(args, "workspace_id")
	if workspaceID == "" {
		workspaceID = "default"
	}

	resp, err := s.client.Approvals.List(ctx, workspaceID)
	if err != nil {
		return errorResult("Failed to list approvals: " + err.Error())
	}

	var pending []map[string]any
	for _, a := range resp.Items {
		if a.Status == "pending" {
			entry := map[string]any{
				"approval_id": a.ApprovalID,
				"intent_id":   a.IntentID,
				"status":      a.Status,
				"requested_at": a.RequestedAt.Format("2006-01-02T15:04:05Z"),
			}
			if a.Rationale != nil {
				entry["rationale"] = *a.Rationale
			}
			pending = append(pending, entry)
		}
	}

	result := map[string]any{
		"count":     len(pending),
		"approvals": pending,
	}
	if len(pending) == 0 {
		result["message"] = "No pending approvals."
	} else {
		result["message"] = fmt.Sprintf("%d pending approval(s).", len(pending))
	}

	return jsonResult(result)
}

// --- Helpers ---

func argStr(args map[string]any, key string) string {
	v, ok := args[key]
	if !ok {
		return ""
	}
	s, ok := v.(string)
	if !ok {
		return ""
	}
	return s
}

func strPtr(s string) *string   { return &s }
func boolPtr(b bool) *bool      { return &b }

func nilIfEmpty(s string) *string {
	if s == "" {
		return nil
	}
	return &s
}

func jsonResult(v any) toolResult {
	data, _ := json.MarshalIndent(v, "", "  ")
	return toolResult{
		Content: []toolContent{{Type: "text", Text: string(data)}},
	}
}

func errorResult(msg string) toolResult {
	return toolResult{
		Content: []toolContent{{Type: "text", Text: msg}},
		IsError: true,
	}
}

func errorResponse(id json.RawMessage, code int, msg string) *jsonrpcResponse {
	return &jsonrpcResponse{
		JSONRPC: "2.0",
		ID:      id,
		Error:   &jsonrpcError{Code: code, Message: msg},
	}
}

// Package main implements the Aileron MCP gateway.
//
// The gateway aggregates tools from downstream MCP servers, re-exposes them
// under namespaced names, and proxies tools/call requests. It also exposes
// the aileron__check_approval meta-tool for checking approval status.

package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"strings"

	"github.com/ALRubinger/aileron/core/config"
	"github.com/ALRubinger/aileron/core/mcpclient"
	"github.com/ALRubinger/aileron/core/vault"
)

const (
	// namespaceSep separates the server name from the tool name in
	// the aggregated tool list (e.g. "github__create_pull_request").
	namespaceSep = "__"

	// checkApprovalTool is the meta-tool for checking approval status.
	checkApprovalTool = "aileron__check_approval"
)

// toolRoute maps a namespaced tool name back to its downstream client and
// the original (un-prefixed) tool name.
type toolRoute struct {
	client       *mcpclient.Client
	originalName string
	serverName   string
}

// gateway manages downstream MCP server connections and tool routing.
type gateway struct {
	clients []*mcpclient.Client
	routes  map[string]toolRoute // namespaced tool name → route
	tools   []toolDef            // aggregated tool list (cached)
	log     *slog.Logger
}

// newGateway connects to all downstream MCP servers defined in cfg, discovers
// their tools, and builds the aggregated tool routing table. Vault-prefixed
// env vars are resolved through v before launching subprocesses.
func newGateway(ctx context.Context, cfg *config.Config, v vault.Vault, log *slog.Logger) (*gateway, error) {
	g := &gateway{
		routes: make(map[string]toolRoute),
		log:    log,
	}

	for _, ds := range cfg.DownstreamServers {
		// Resolve vault:// env vars.
		env, err := resolveEnv(ctx, ds.Env, v)
		if err != nil {
			return nil, fmt.Errorf("gateway: server %q: %w", ds.Name, err)
		}

		// Convert map to KEY=VALUE slice for subprocess.
		envSlice := make([]string, 0, len(env))
		for k, val := range env {
			envSlice = append(envSlice, k+"="+val)
		}

		client, err := mcpclient.NewClient(ctx, ds.Name, ds.Command, envSlice)
		if err != nil {
			// Clean up any already-started clients.
			g.closeAll()
			return nil, fmt.Errorf("gateway: start server %q: %w", ds.Name, err)
		}

		g.clients = append(g.clients, client)

		// Register each tool with a namespaced name.
		for _, tool := range client.Tools() {
			qualifiedName := ds.Name + namespaceSep + tool.Name
			g.routes[qualifiedName] = toolRoute{
				client:       client,
				originalName: tool.Name,
				serverName:   ds.Name,
			}
			g.tools = append(g.tools, toolDef{
				Name:        qualifiedName,
				Description: fmt.Sprintf("%s (via %s)", tool.Description, ds.Name),
				InputSchema: toSchema(tool.InputSchema),
			})
		}

		log.Info("connected downstream server",
			"name", ds.Name,
			"tools", len(client.Tools()),
		)
	}

	// Always add the check_approval meta-tool.
	g.tools = append(g.tools, checkApprovalToolDef())

	return g, nil
}

// aggregatedTools returns the full list of tools from all downstream servers
// plus the aileron meta-tools.
func (g *gateway) aggregatedTools() []toolDef {
	return g.tools
}

// routeToolCall dispatches a tool call to the appropriate downstream server.
// For the meta-tool, it handles the call internally. For proxied tools, it
// forwards to the downstream MCP server and returns the result.
func (g *gateway) routeToolCall(ctx context.Context, name string, arguments map[string]any) toolResult {
	if name == checkApprovalTool {
		return g.handleCheckApproval(ctx, arguments)
	}

	route, ok := g.routes[name]
	if !ok {
		return toolResult{
			Content: []toolContent{{Type: "text", Text: "Unknown tool: " + name}},
			IsError: true,
		}
	}

	result, err := route.client.CallTool(ctx, route.originalName, arguments)
	if err != nil {
		return toolResult{
			Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Error calling %s: %v", name, err)}},
			IsError: true,
		}
	}

	// Convert mcpclient.ToolResult to local toolResult.
	var content []toolContent
	for _, c := range result.Content {
		content = append(content, toolContent{Type: c.Type, Text: c.Text})
	}
	return toolResult{
		Content: content,
		IsError: result.IsError,
	}
}

// handleCheckApproval is a stub for the approval-checking meta-tool.
// Full implementation comes in Phase 2 when policy interception is added.
func (g *gateway) handleCheckApproval(_ context.Context, args map[string]any) toolResult {
	approvalID := argStr(args, "approval_id")
	if approvalID == "" {
		return errorResult("approval_id is required")
	}

	// Phase 2 will integrate with the approval orchestrator here.
	return jsonResult(map[string]any{
		"approval_id": approvalID,
		"status":      "not_implemented",
		"message":     "Approval checking will be available when policy interception is enabled.",
	})
}

// closeAll terminates all downstream client connections.
func (g *gateway) closeAll() {
	for _, c := range g.clients {
		if err := c.Close(); err != nil {
			g.log.Warn("error closing downstream server",
				"name", c.Name(),
				"error", err,
			)
		}
	}
}

// resolveEnv resolves vault:// prefixed env values using the vault, or
// passes them through unchanged. If vault is nil, vault:// references are
// treated as an error.
func resolveEnv(ctx context.Context, env map[string]string, v vault.Vault) (map[string]string, error) {
	if len(env) == 0 {
		return nil, nil
	}

	vaultGet := func(path string) ([]byte, error) {
		if v == nil {
			return nil, fmt.Errorf("vault not available; cannot resolve vault://%s", path)
		}
		secret, err := v.Get(ctx, path)
		if err != nil {
			return nil, err
		}
		return secret.Value, nil
	}

	return config.ResolveVaultEnv(env, vaultGet)
}

// checkApprovalToolDef returns the tool definition for the aileron meta-tool.
func checkApprovalToolDef() toolDef {
	return toolDef{
		Name:        checkApprovalTool,
		Description: "Check the status of a pending approval. If the action has been approved, the original tool call is automatically executed and its result is returned.",
		InputSchema: schema{
			Type: "object",
			Properties: map[string]schemaProp{
				"approval_id": {Type: "string", Description: "The approval ID returned when a tool call was held for approval"},
			},
			Required: []string{"approval_id"},
		},
	}
}

// toSchema converts a generic map (from MCP tools/list) to our schema type.
// If the input is nil or empty, a minimal object schema is returned.
func toSchema(raw map[string]any) schema {
	if raw == nil {
		return schema{Type: "object"}
	}

	s := schema{Type: "object"}

	if t, ok := raw["type"].(string); ok {
		s.Type = t
	}

	if props, ok := raw["properties"].(map[string]any); ok {
		s.Properties = make(map[string]schemaProp, len(props))
		for name, v := range props {
			prop := schemaProp{}
			if pm, ok := v.(map[string]any); ok {
				if t, ok := pm["type"].(string); ok {
					prop.Type = t
				}
				if d, ok := pm["description"].(string); ok {
					prop.Description = d
				}
			}
			s.Properties[name] = prop
		}
	}

	if req, ok := raw["required"].([]any); ok {
		for _, r := range req {
			if rs, ok := r.(string); ok {
				s.Required = append(s.Required, rs)
			}
		}
	}

	return s
}

// lookupRoute returns the route for a namespaced tool name, if it exists.
func (g *gateway) lookupRoute(qualifiedName string) (toolRoute, bool) {
	r, ok := g.routes[qualifiedName]
	return r, ok
}

// serverNameFromQualified extracts the server name from a namespaced tool name.
func serverNameFromQualified(qualifiedName string) string {
	if idx := strings.Index(qualifiedName, namespaceSep); idx >= 0 {
		return qualifiedName[:idx]
	}
	return ""
}

// originalNameFromQualified extracts the original tool name from a namespaced tool name.
func originalNameFromQualified(qualifiedName string) string {
	if idx := strings.Index(qualifiedName, namespaceSep); idx >= 0 {
		return qualifiedName[idx+len(namespaceSep):]
	}
	return qualifiedName
}

