		t.Errorf("len after peek = %d, want 1", q.len())
	}
}

func TestQueuedCall_Summary(t *testing.T) {
	call := queuedCall{
		ServerName: "github",
		ToolName:   "create_pr",
	}
	want := "create_pr (via github)"
	if got := call.summary(); got != want {
		t.Errorf("summary = %q, want %q", got, want)
	}
}

